/* 7e18fa727632fb2c274aa4ff00e7335f69d7b03a */ import axios from 'axios'; export default { name: 'trivia', alias: ['quiz', 'triv'], category: 'games', description: 'Answer trivia questions 🧠', async execute(wy, xl, xp, te) { const chatId = xl.key.remoteJid; const yo = xl.sq || 'Friend'; if (!global.triviaGames) global.triviaGames = new Map(); const game = global.triviaGames.get(chatId); if (game) { const answer = xp.join(' ').toLowerCase().trim(); const correct = game.correctAnswer.toLowerCase(); if (answer === correct || game.options?.some(opt => opt.toLowerCase() === answer)) { await wy.sendMessage(chatId, { text: `┌─⧭ *✅ CORRECT!* ⧭─┐ │ ├─⧭ *Answer:* ${game.correctAnswer} ├─⧭ *Winner:* ${yo} │ │ Well done! 🏆 │ └─⧭🦊` }, { quoted: xl }); global.triviaGames.delete(chatId); } else { await wy.sendMessage(chatId, { text: `┌─⧭ *❌ WRONG!* ⧭─┐ │ ├─⧭ Try again! │ └─⧭🦊` }, { quoted: xl }); } return; } try { const response = await axios.get('https://opentdb.com/api.php?amount=1&type=multiple'); const data = response.data.results[0]; const question = data.question.replace(/&quot;/g, '"').replace(/&#039;/g, "'"); const correctAnswer = data.correct_answer; const options = [...data.incorrect_answers, correctAnswer]; for (let i = options.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [options[i], options[j]] = [options[j], options[i]]; } const optionLetters = ['A', 'B', 'C', 'D']; const optionsDisplay = options.map((opt, i) => `${optionLetters[i]}. ${opt.replace(/&quot;/g, '"').replace(/&#039;/g, "'")}` ).join('\n│ '); global.triviaGames.set(chatId, { correctAnswer, options, startTime: Date.now() }); await wy.sendMessage(chatId, { text: `┌─⧭ *TRIVIA QUIZ* 🧠 ⧭─┐ │ ├─⧭ *Category:* ${data.category} ├─⧭ *Difficulty:* ${data.difficulty} │ ├─⧭ *Question:* │ ${question} │ ├─⧭ *Options:* │ ${optionsDisplay} │ ├─⧭ *Answer with:* │ ${te}trivia A │ ${te}trivia answer │ └─⧭🦊 *First to answer wins!*` }, { quoted: xl }); setTimeout(() => { if (global.triviaGames.has(chatId)) { wy.sendMessage(chatId, { text: `┌─⧭ *⏰ TIME'S UP!* ⧭─┐ │ ├─⧭ The correct answer was: │ ${correctAnswer} │ └─⧭🦊` }, { quoted: xl }); global.triviaGames.delete(chatId); } }, 60000); } catch (error) { await wy.sendMessage(chatId, { text: `┌─⧭ *ERROR* ❌ ⧭─┐ │ ├─⧭ Could not fetch trivia question. │ └─⧭🦊` }, { quoted: xl }); } await wy.sendMessage(chatId, { react: { text: "🧠", key: xl.key } }); } };